// Build a reputation digest from the StayingAPI /v1/reviews response.
// Input item: { data: Review[], meta: SuccessMeta }.
const STOP = new Set(
  ('the a an and or but to of in on for with was were is are it we they i you this that had have ' +
   'has very really just so at as our my me not no all had them their there here would could stay ' +
   'stayed place property host would great good nice')
    .split(' '),
);
const out = [];
for (const item of $input.all()) {
  const reviews = Array.isArray(item.json.data) ? item.json.data : [];
  const meta = item.json.meta || {};
  const scale = reviews[0]?.ratingScale ?? 5;
  const rated = reviews.filter((r) => typeof r.rating === 'number');
  const avg = rated.length
    ? Math.round((rated.reduce((s, r) => s + r.rating, 0) / rated.length) * 100) / 100
    : null;
  const lowThreshold = scale * 0.6;
  const low = rated.filter((r) => r.rating <= lowThreshold);
  const freq = {};
  for (const r of reviews) {
    for (const w of String(r.text || '')
      .toLowerCase()
      .replace(/[^a-z\s]/g, ' ')
      .split(/\s+/)) {
      if (w.length < 4 || STOP.has(w)) continue;
      freq[w] = (freq[w] || 0) + 1;
    }
  }
  const themes = Object.entries(freq)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 8)
    .map(([w, c]) => `${w} (${c})`);
  const recentComplaints = low
    .slice(0, 5)
    .map((r) => `• ${r.rating}/${r.ratingScale} — ${String(r.text || '').slice(0, 140)} (${r.author ?? '?'}, ${r.date ?? ''})`);
  const report =
    `Review digest — ${reviews.length} reviews (avg ${avg ?? 'n/a'}/${scale})\n\n` +
    `Top themes: ${themes.join(', ') || 'n/a'}\n\n` +
    (recentComplaints.length
      ? `Recent low ratings (${low.length}):\n${recentComplaints.join('\n')}\n\n`
      : `No recent low ratings.\n\n`) +
    `Credits charged: ${meta.creditsCharged ?? 0} · requestId ${meta.requestId ?? ''}`;
  out.push({
    json: {
      count: reviews.length,
      avgRating: avg,
      ratingScale: scale,
      themes,
      lowRatingCount: low.length,
      recentComplaints,
      report,
    },
  });
}
return out;
